// G-ECharts default chart
let xAxisData = [];
let seriesData = [];
for (const f of data.series[0].fields) {
  if (f.type === 'time') {
    xAxisData = f.values.map((t) => new Date(t).toLocaleTimeString());
  } else if (f.type === 'number') {
    seriesData = f.values;
  }
}
return {
  title: { text: 'Default chart (Billiballa\'s area-line example)', left: 'center' },
  tooltip: { trigger: 'axis' },
  xAxis: { type: 'category', data: xAxisData, boundaryGap: false },
  yAxis: { type: 'value' },
  series: [{
    type: 'line',
    data: seriesData,
    smooth: true,
    areaStyle: { opacity: 0.3 },
    lineStyle: { width: 2 },
  }],
};

// Bar chart from time-series
const valueField = data.series[0].fields.find((f) => f.type === 'number');
const timeField = data.series[0].fields.find((f) => f.type === 'time');
return {
  title: { text: 'Bar chart example', left: 'center' },
  tooltip: { trigger: 'axis' },
  grid: { left: 50, right: 20, top: 50, bottom: 30 },
  xAxis: {
    type: 'category',
    data: timeField.values.slice(-12).map((t) => new Date(t).toLocaleTimeString()),
  },
  yAxis: { type: 'value' },
  series: [{ type: 'bar', data: valueField.values.slice(-12) }],
};

// Pie chart aggregated across series
const slices = data.series.map((s, i) => ({
  name: s.name || `Series ${i + 1}`,
  value: Math.abs(
    s.fields
      .find((f) => f.type === 'number')
      .values.reduce((a, b) => a + b, 0)
  ),
}));
return {
  title: { text: 'Pie chart example', left: 'center' },
  tooltip: { trigger: 'item' },
  legend: { bottom: 0 },
  series: [{
    type: 'pie',
    radius: ['40%', '65%'],
    center: ['50%', '50%'],
    data: slices,
    label: { show: true, formatter: '{b}: {d}%' },
  }],
};
